<script lang="ts">import TabsRoot from '@fex/components-svelte/primitive/tabs-root'; import TabsList from '@fex/components-svelte/primitive/tabs-list'; import TabsItem from '@fex/components-svelte/primitive/tabs-item'; import TabsContent from '@fex/components-svelte/primitive/tabs-content'; import Card from '@fex/components-svelte/ui/card'; import { createTab, initialTabs } from './data'; let items = $state([...initialTabs]); let value = $state('overview'); let nextIndex = $state(4); function add() { const item = createTab(nextIndex++); items = [...items, item]; value = item.value } function remove(target: string) { const index = items.findIndex((item) => item.value === target); items = items.filter((item) => item.value !== target); if (value === target) value = items[Math.min(index, items.length - 1)]?.value ?? '' }</script>
<Card title="Add, remove and extra" description="Application data drives primitive Items and Contents."><TabsRoot {value} onchange={(next) => value = next ?? ''} onclose={(item) => remove(item.value)}><div class="flex min-w-0 items-center gap-space-sm"><span class="text-xs text-muted-foreground">Workspace</span><TabsList class="min-w-0 flex-1">{#each items as item (item.value)}<TabsItem value={item.value} closable={item.closable}>{item.label}</TabsItem>{/each}</TabsList><button class="rounded-md border border-border px-2 py-1 text-xs" type="button" onclick={add}>Add</button></div>{#each items as item (item.value)}<TabsContent value={item.value}>{item.content}</TabsContent>{/each}</TabsRoot></Card>
